var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"전력 복구 완료… 자동항행 시스템 활성화…","JPN":"電力復旧完了……自動航行システム活性化……","ENG":"Power restoration complete... Autopilot system activated...","TWN":"能源恢復完成…… 自動航行系統啟動……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"차원 단층 진입 성공…/","JPN":"次元断層進入成功……/","ENG":"Dimensional strata entry successful...","TWN":"成功進入次元斷層……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"스읍-","JPN":"すうっー","ENG":"*Inhale*","TWN":"吸——"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하아아-","JPN":"はああー","ENG":"*Exhale*","TWN":"呼——"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다행히 숨구멍이 늘어난 것 같진 않네요.","JPN":"よかった、穴が開いたりはしてないみたいです。","ENG":"Thank goodness I don't have additional windpipes.","TWN":"謝天謝地，好像沒有多個呼吸孔。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저희, 무사한 거 맞죠?","JPN":"私たち、無事なんですよね？","ENG":"We're in the clear, right?","TWN":"我們真的沒事吧……？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"예. 폭발의 여파에 휘말리긴 했지만, 벗어나는데 성공했군요.","JPN":"はい。爆発の余波に巻き込まれましたが、抜け出すことに成功しましたね。","ENG":"Yes. We were caught in the aftermath of the explosion, but we managed to escape.","TWN":"是的。雖然被捲入了轟炸的餘波，但成功脫身了。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"급한대로 폐병원에서 입수한 좌표를 입력해서 어디로 향하는진 알 수 없지만요.","JPN":"とりあえず廃病院から入手した座標を入力しました。どこに向かっているのかはわかりませんが。","ENG":"But we don't know where we're headed, since we punched in the coordinates from the abandoned hospital in a hurry.","TWN":"但我們不知道會去到哪，因為倉促間輸入的是從廢棄醫院那裡獲取的座標。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정확히 5분 걸렸군. 조금은 더 여유를 줄 거라 생각했는데 말이지.","JPN":"確かに5分かかったな。もう少し余裕があると思ったんだが。","ENG":"It took exactly 5 minutes. I thought they'd give us some slack.","TWN":"正好5分鐘。我還以為會稍微寬裕一點呢。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"호의를 베푸는 척했지만, 사실 저희를 제거하고 싶었던 거 아닐까요?","JPN":"厚意を施すふりをしておきながら、実は私たちを排除したかったんじゃないでしょうか？","ENG":"They pretended to be friendly, but maybe they just wanted to get rid of us.","TWN":"那個女人表面上裝作好心，實際是想除掉我們吧……？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴지도 모르지.","JPN":"そうかもしれないな。","ENG":"Perhaps so.","TWN":"也許吧。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 차원도약이 잘 작동해준 덕에 탈출은 했잖나.","JPN":"だが次元跳躍がちゃんと作動してくれたおかげで脱出はできただろう？","ENG":"Still, we did escape in one piece thanks to the dimension jump working well.","TWN":"不過幸好次元跳躍的功能正常，我們才得以逃脫。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님의 긍정 마인드는 저도 본받고 싶네요.","JPN":"社長のポジティブマインドは私も見習いたいです。","ENG":"I should really learn how to stay positive like you, Boss.","TWN":"老闆那種正能量我一直都想好好學習呢……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 자가 저희 목숨을 위협했다는 건 분명한 사실입니다.","JPN":"あの者が私たちの命を脅かしたのは確かな事実です。","ENG":"It is true that she threatened our lives.","TWN":"然而那個人確實威脅到了我們的性命。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"관리자님께서 적을 비난하지 않고 의중을 헤아리는 것은 그런 훌륭한 성품을 지니셨기 때문이죠.","JPN":"最高管理者様が敵を責めずにその心を推し量ろうとするのは、立派な品性をお持ちだからでしょう。","ENG":"But it's because of your outstanding character that you didn't criticize the enemy and tried to understand their intentions.","TWN":"管理者不僅沒有指責敵人，而是體諒他們的意圖，這正是他所擁有的優秀品格。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하하…","JPN":"はは……","ENG":"Haha...","TWN":"哈哈……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"좌표 지점 도착.","JPN":"座標地点に到着。","ENG":"Arrived at the designated coordinates.","TWN":"到達座標地點。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"다이브 아웃까지 남은 시간, 3분…","JPN":"ダイブアウトまで、あと3分……","ENG":"3 minutes remaining until dive out...","TWN":"距離躍入結束還有……3分鐘……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"궁금한 게 있는데요.","JPN":"気になることがあるんですけど。","ENG":"I have a question.","TWN":"我有一個問題。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"대체 이 그라운드 제로라는 곳 아래엔 뭐가 있는 거죠?","JPN":"このグラウンド・ゼロの下には、いったい何があるんですか？","ENG":"What's under that Ground Zero place?","TWN":"在這個G0底下究竟有什麼？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 대균열들만큼 위험하진 않지만, 그라운드 제로도 그 정의는 비슷하다네.","JPN":"他の大亀裂ほど危険ではないが、グラウンド・ゼロもその定義は似たようなものだ。","ENG":"It isn't as dangerous as the other Crevices, but Ground Zero is similar by definition.","TWN":"雖然沒有其他大峽谷那麼危險，但從定義來講，G0也是差不多的存在。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대균열은 현실이 이면세계와 직접 맞닿아 있는, 인류에게 가장 위협이 되는 장소를 뜻하지.","JPN":"大亀裂とは現実が裏世界と直に接していて、人類にとってもっとも脅威的な場所を意味する。","ENG":"A Grand Dimension Crevice is a location that poses the greatest threat to humanity as it is where the Normalside and the Counterside come into direct contact.","TWN":"大峽谷是現實與異界直接交接的地方，對人類來說是最具威脅的場所。"},"stage":{"bg":"MS_1204_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"현재 남아있는 여섯 대균열과 달리 그라운드 제로는 관리국이 건재하던 시절, 처음으로 봉쇄에 성공한 균열이야.","JPN":"現在残っている6か所の大亀裂とは違い、グラウンド・ゼロは管理局が健在だった頃に初めて封鎖に成功した亀裂だ。","ENG":"Unlike the remaining six Crevices, Ground Zero is the first that was successfully sealed when the Administration still existed.","TWN":"與目前剩下的六個大峽谷不同，G0是管理局還在的時候，首次成功封鎖的裂縫。"},"stage":{"bg":"MS_1204_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 너머에 숨겨진 이면세계는… 한때 침식에 맞서 싸웠던 인류의 터전이기도 하지.","JPN":"そしてその向こう側に隠された裏世界は……かつて侵食に立ち向かい戦った人類の住処でもある。","ENG":"And the Counterside hidden beyond it is... also the home of humanity that once fought against Corruption.","TWN":"而隱藏在它之後的異界……曾經也是那些與侵蝕作戰的人類的據點。"},"stage":{"bg":"MS_1204_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이면세계가 우리가 알던 현실이라고요?","JPN":"裏世界が、私たちの知っている現実だってことですか？","ENG":"The Counterside is the Normalside we know?","TWN":"這個異界也是我們所熟悉的現實世界嗎……？"},"stage":{"bg":"MS_1204_01","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 여긴 온통 침식체 뿐인 걸요.","JPN":"でも、ここには侵食体しかいないんですよ？","ENG":"But it's crawling with C.O.s here.","TWN":"但這裡全是侵蝕體啊。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세계가 처음부터 이런 황무지였던 건 아닐세.","JPN":"この世界が最初からこんな荒れ地だったわけではない。","ENG":"This world wasn't a wasteland from the beginning.","TWN":"這個世界從一開始並不是這樣的荒地。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"적어도 우리… 아니, 관리자인 내가 클리포트 게임에서 패배하기 전까진 그랬지.","JPN":"少なくとも私たち……いや、管理者である私がクリフォトゲームで敗北するまではな。","ENG":"Well, at least not until we–I mean, I, the Administrator, lost the Qliphoth Game.","TWN":"至少我們……不，作為管理者的我在逆卡巴拉遊戲中失敗之前不是如此。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"패배라고요? 하지만 클리포트 게임은 이겼다고 들었는데, 아닌가요?","JPN":"敗北？　でもクリフォトゲームで勝利したって聞いたんですけど、違うんですか？","ENG":"Lost? But I heard we won, didn't we?","TWN":"失敗了？可我聽說是我們贏了，不是嗎？"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 이번엔 분명히 승리했네.","JPN":"ああ。今回は確かに勝利した。","ENG":"Yes. We won this time.","TWN":"好吧，這次確實贏了。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 승리에 이르기까지, 난 수많은 <color=#ffd34c>실패</color>를 겪어왔어.","JPN":"だがその勝利に至るまで、私は数多くの<color=#ffd34c>失敗</color>を経験してきた。","ENG":"But to achieve that single victory, I had to face countless <color=#ffd34c>failures</color>.","TWN":"但是在到達那次勝利之前，我已經經歷了無數次的<color=#ffd34c>失敗</color>。"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 실패의 대가로 치러야 했던 과거가…","JPN":"そしてその失敗の代価として払わなければならなかった過去が……","ENG":"And the past I had to pay for those failures...","TWN":"而那段必須為失敗付出代價的過去……"},"stage":{"bg":"HELI_NIGHT_3","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바로 이곳에 묻혀 있다네.","JPN":"ここに埋もれているのだ。","ENG":"It is buried here.","TWN":"就埋葬在這個地方。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"다이브 아웃, 성공…","JPN":"ダイブアウト、成功……","ENG":"Dive out, success...","TWN":"躍出，成功……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"경고… 높은 밀도의 침식파 감지…","JPN":"警告……高密度の侵食波を感知……","ENG":"Warning... Detecting high-density Corruption rays...","TWN":"警告……檢測到高密度侵蝕波……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그랬었군요.","JPN":"そうだったのですね。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"구 관리국의 존재를 감안하더라도, 관리국이 통제하는 이면세계에 대해선 여러 의문점들이 떠돌았죠.","JPN":"旧管理局の存在を考慮しても、管理局が統制している裏世界については様々な疑問点がありました。","ENG":"Even taking the Old Administration into account, there were many questions floating around about the Counterside controlled by the Administration.","TWN":"即使考慮到舊管理局的存在，我們對於管理局所能掌控的異界，仍然有許多疑問。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"출처를 알 수 없는 노후화 된 관리국제 장비… 현대의 생존자와 유전자 샘플이 일치하는 시신… 그리고 시대를 초월한 기술력으로 만들어진 차원함선, 로스트 쉽까지.","JPN":"出所がわからない老朽化した管理局製の装備……現代の生存者と遺伝子のサンプルが一致する遺体……そして時代を超越した技術力で作られた次元艦船、ロストシップまで。","ENG":"Old and worn Administration-crafted gear of unknown origin... Corpses whose DNA samples match those of a person living in the modern day... And even Lost Ships, the dimensional ships made with technology that transcends eras.","TWN":"陳舊且來歷不明的管理局裝備……DNA樣本與現代倖存者相匹配的遺體……以及用超越時代的技術製造的次元艦船。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"만약 관리국이 모종의 수단을 통해 재건과 실패를 반복했고, 그 흔적이 이면세계라는 형태로 남았다면… 모든 게 설명이 되는군요.","JPN":"もし管理局がある手段を通じて再建と失敗を繰り返し、その痕跡が裏世界という形で残っているなら……すべて説明がつきますね。","ENG":"If the Administration repeated the construction and collapsed through some kind of means, and those traces were left in the form of the Counterside... it explains everything.","TWN":"如果管理局透過某種手段反復進行重建，並經歷了失敗，而這些痕跡都以異界的形式保留了下來……一切都解釋得通了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 말씀대로라면… 여기도 한땐 지금 세상이랑 별반 다르지 않았단 걸까요?","JPN":"おっしゃるとおりなら……ここもかつては今の世界とそう変わらなかったのでしょうか？","ENG":"Then like you said... this place wouldn't have been much different from the world we live in now at one point, right?","TWN":"照你這麼說……這裡曾經和現在的世界沒什麼兩樣嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだな。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비록 지금 우릴 반겨주는 건, 잿더미 위에 남은 침식체들 뿐이지만 말이야.","JPN":"今私たちを迎え入れてくれるのは、灰の上に残った侵食体だけだが。","ENG":"Even if C.O.s on top of ashes are the only ones here to welcome us now.","TWN":"雖說現在能來歡迎我們的，是站在灰燼上的侵蝕體。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};